[FormDataSourceEventHandler(formDataSourceStr(SalesAgreement, ALine), FormDataSourceEventType::Written)]
public static void ALine_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETG_SalesAgreementLine   salesAgreementLine; 
    AgreementLine           agreementline   = sender.cursor();

    FormDataSource          salesAgreementHeader_ds       = sender.formRun().dataSource('ETG_SalesAgreementHeader');
    ETG_SalesAgreementHeader    salesAgreementHeaderETG   = salesAgreementHeader_ds.cursor();

    salesAgreementLine.SalesAgreementId = salesAgreementHeaderETG.SalesAgreementId;
    salesAgreementLine.SalesAgreementLine = agreementline.RecId;
    salesAgreementLine.insert();
}
